import fs from 'fs';
import path from 'path';

export interface DetectionResult {
    dockerfile: string;
    dockerignore: string;
    internalPort: number;
    framework: string;
}

export function detectAppType(appPath: string): DetectionResult {
    const pkgPath = path.join(appPath, 'package.json');
    const hasPkg = fs.existsSync(pkgPath);

    const commonIgnore = `
node_modules
.next
dist
.git
*.zip
Dockerfile
.dockerignore
`.trim();

    if (hasPkg) {
        const pkg = JSON.parse(fs.readFileSync(pkgPath, 'utf-8'));
        const deps = { ...pkg.dependencies, ...pkg.devDependencies };

        if (deps['next']) {
            return {
                framework: 'Next.js',
                internalPort: 3000,
                dockerignore: commonIgnore,
                dockerfile: `
FROM node:18-alpine
WORKDIR /app
COPY package*.json ./
RUN npm install
COPY . .
# Next.js build often needs more memory
ENV NODE_OPTIONS="--max-old-space-size=4096"
RUN npm run build
EXPOSE 3000
CMD ["npm", "start"]
`.trim(),
            };
        }

        // Generic Node.js / Vite / etc.
        return {
            framework: 'Node.js',
            internalPort: 5173,
            dockerignore: commonIgnore,
            dockerfile: `
FROM node:18-alpine
WORKDIR /app
COPY package*.json ./
RUN npm install
COPY . .
RUN npm run build
RUN npm install -g serve
EXPOSE 5173
CMD ["serve", "-s", "dist", "-l", "5173"]
`.trim(),
        };
    }

    // Fallback to Static HTML
    return {
        framework: 'Static HTML',
        internalPort: 80,
        dockerignore: commonIgnore,
        dockerfile: `
FROM nginx:alpine
COPY . /usr/share/nginx/html
EXPOSE 80
`.trim(),
    };
}
